<?php class AdminerTablesHide{public $hiddenTables=[];public function __construct($hiddenTables=[]){$this->hiddenTables=$hiddenTables;}public function getHiddenTablesForCurrentDatabase(){$currentDatabase=$_GET["db"]??null;if($currentDatabase!==null&&isset($this->hiddenTables[$currentDatabase])&&is_array($this->hiddenTables[$currentDatabase])){return $this->hiddenTables[$currentDatabase];}if(!empty($this->hiddenTables)){$firstValue=reset($this->hiddenTables);if(!is_array($firstValue)){return $this->hiddenTables;}}return [];}public function tablesPrint($tables){$hiddenTablesForDatabase=$this->getHiddenTablesForCurrentDatabase();$jsonTables=[];foreach($tables as $table=>$status){$jsonTables[]=['table'=>$table,'isView'=>Adminer\is_view($status),'show'=>Adminer\support("table")||Adminer\support("indexes"),'selected'=>in_array($table,[$_GET["table"]??null,$_GET["create"]??null,$_GET["indexes"]??null,$_GET["foreign"]??null,$_GET["trigger"]??null,$_GET["select"]??null,$_GET["edit"]??null,$_GET["view"]??null]),'fullTableName'=>($_GET[Adminer\DRIVER]??'')."-".($_GET["db"]??'')."-".$table];}?> <style<?php echo Adminer\nonce(); ?>>p.toggleTableVisible{cursor:pointer}#menu.hiddenVisible .hideT{display:inline}.hideT,#tables li.hiddenTable,#menu.hiddenVisible .showT{display:none}#menu.hiddenVisible #tables li.hiddenTable{display:inline;opacity:.5}#tables li.filtered,#menu.hiddenVisible #tables li.hiddenTable.filtered{display:none}#tables a.toggleVisible{background-image:url(data:image/png;base64,);display:inline-block;height:10px;visibility:hidden;width:13px}#tables li.hiddenTable a.toggleVisible{background-image:url(data:image/png;base64,)}#tables.min a.toggleVisible{visibility:visible}</style><p class="jsonly">Filter: <input id="filterInput"></p><ul id="tables"></ul><p class="toggleTableVisible"><span class="showT">Show</span><span class="hideT">Hide</span> hidden tables</p><script<?php echo Adminer\nonce(); ?>>var menuTables=<?php echo json_encode($jsonTables); ?>;<?php $forced