n.classList.add("hiddenTable")}var showHideButton=document.createElement("a");showHideButton.href="#"+encodeURIComponent(menuTables[i].table);showHideButton.className="toggleVisible";var selectA=document.createElement("a");selectA.appendChild(document.createTextNode(selectLang));selectA.href=baseUrl+"select="+encodeURIComponent(menuTables[i].table);selectA.className="select"+(menuTables[i].isView?" is-view":"");var structureA=document.createElement("a");structureA.appendChild(highlightFoundPart(menuTables[i].table,value));structureA.href=baseUrl+"table="+encodeURIComponent(menuTables[i].table);structureA.title=structureLang;spn.appendChild(showHideButton);spn.appendChild(document.createTextNode(" "));spn.appendChild(selectA);spn.appendChild(document.createTextNode(" "));spn.appendChild(structureA);tablesEl.appendChild(spn).appendChild(document.createElement("br"))}}}function highlightFoundPart(name,search){if(search==""){return document.createTextNode(name)}var wrap=document.createElement("span");wrap.className="noBg";var startIndex=name.indexOf(search);if(startIndex>0){wrap.appendChild(document.createTextNode(name.substring(0,startIndex)))}var strongEl=document.createElement("strong");strongEl.appendChild(document.createTextNode(name.substring(startIndex,startIndex+search.length)));wrap.appendChild(strongEl);if(name.length>startIndex+search.length){wrap.appendChild(document.createTextNode(name.substring(startIndex+search.length)))}return wrap}function menuOverATH(e){menuOver.call(this,e);this.classList.add("min")}function menuOutATH(e){menuOut.call(this,e);this.classList.remove("min")}mixin(qs("#filterInput"),{onkeyup:filterTables});mixin(qs(".toggleTableVisible"),{onclick:bclick});mixin(qs('#tables'),{onmouseover:menuOverATH,onmouseout:menuOutATH});tablesEl.addEventListener("click",function(e){var t=e.target,ret=true;while(t&&t!==this){if(t.matches("a.toggleVisible")){if(toggleVisible.call(t,event)===false){ret=false}}t=t.parentNode}return ret});initTables();document.addEventListener("DOMContentLoaded",function(){if(forcedHiddenTableNames.length===0)return;var contentTable=document.querySelector("div.scrollable table.nowrap.checkable");if(!contentTable)return;var rows=contentTable.querySelectorAll("tbody tr");rows.forEach(function(row){var checkbox=row.querySelector("input[name='tables[]']");if(!checkbox)return;var tableName=checkbox.value;if(forcedHiddenTableNames.indexOf(tableName)>=0){row.style.display="none"}})});</script><?php return true;}}
